    toolName: "find_arbitrage_opportunities",
    args: {
      category: "politics",
      limit: 20
    }
  });

  const arbitrage = Array.isArray(result?.arbitrageOpportunities) ? result.arbitrageOpportunities : [];
  const wideSpreads = Array.isArray(result?.wideSpreadMarkets) ? result.wideSpreadMarkets : [];

  const rankedArb = [...arbitrage].sort((a, b) => {
    const ae = typeof a?.potentialEdge === "number" ? a.potentialEdge : -Infinity;
