  const trendingMarketsData = trendingMarkets?.status === "fulfilled" ? trendingMarkets.value : null;

  const candidates = [];
  const seen = new Set();

  const addCandidates = (items, source) => {
    if (!Array.isArray(items)) return;
    for (const item of items) {
      if (!item) continue;
      const slug = item.slug;
      const conditionId = item.conditionId;
      const title = item.title;
      if (!slug || seen.has(slug)) continue;
      seen.add(slug);
      candidates.push({
        slug,
        conditionId,
        title,
        url: item.url,
        liquidity: item.liquidity,
        volume24h: item.volume24h,
        currentPrice: item.currentPrice,
        source
      });
    }
  };

  addCandidates(topMarketsData?.markets, "get_top_markets");
  addCandidates(trendingMarketsData?.trendingMarkets, "discover_trending_markets");

  const politicsCandidates = candidates.filter((m) => m.slug || m.conditionId);

  const rankedCandidates = pickTopSemanticCandidates({
    target: "most liquid live multi-outcome politics event on Polymarket",
    candidates: politicsCandidates,
    requiredTerms: ["politics"],
    avoidTerms: ["resolved", "closed"],
    limit: 8
  });

  const shortlist = rankedCandidates.filter((m) => Number(m.liquidity) > 0).slice(0, 5);

  let selectedEvent = null;
  let selectedOutcomes = [];
  let selectedOutcomesResult = null;

