    const outcomesResult = await callMcpSkill({
      toolId,
      toolName: "get_event_outcomes",
      args: {
        slug: candidate.slug,
        sortBy: "volume"
      }
    });

    const outcomes = Array.isArray(outcomesResult?.outcomes) ? outcomesResult.outcomes : [];
    const liveMultiOutcome = outcomes.length > 2;

    if (liveMultiOutcome) {
      selectedEvent = {
        title: outcomesResult.eventTitle || candidate.title,
        slug: candidate.slug,
        url: candidate.url,
        conditionId: candidate.conditionId,
        liquidity: candidate.liquidity,
        volume24h: candidate.volume24h,
        source: candidate.source
      };
      selectedOutcomes = outcomes;
      selectedOutcomesResult = outcomesResult;
      break;
    }
  }

  if (!selectedEvent) {
    return {
      status: "no_match",
      attemptedBranches: ["parallel probe", "semantic shortlist", "sequential outcome validation"],
      missingData: {
        reason: "No verified live multi-outcome politics event was confirmed from the probed shortlist.",
        probedCount: candidates.length
      },
      probe: {
        topMarkets: topMarketsData,
        trendingMarkets: trendingMarketsData
      }
    };
  }

  const rankedOutcomes = selectedOutcomes
    .slice()
    .sort((a, b) => (b?.price ?? 0) - (a?.price ?? 0))
    .slice(0, 4);

  const outcomeNames = rankedOutcomes.map((o) => o?.name).filter(Boolean);

  const comparison = await callMcpSkill({
    toolId,
    toolName: "compare_event_outcome_quotes",
    args: {
      eventQuery: selectedEvent.title,
      outcomes: outcomeNames,
      category: "politics"
    }
  });

  const liquidity = await callMcpSkill({
    toolId,
    toolName: "analyze_event_outcome_liquidity",
    args: {
      slug: selectedEvent.slug,
      outcomes: outcomeNames,
      limit: 4,
      sortBy: "volume"
    }
  });

