import { callMcpSkill } from "@/lib/ai/skills/mcp";

export async function main() {
  const toolId = "294100e8-c648-4e5f-a254-95a14b56e398";

  const result = await callMcpSkill({
    toolId,
    toolName: "analyze_single_market_whales",
    args: {
      marketQuery: "Fed decision",
    },
  });

  const selectedMarket = result.selectedMarket || {};
  const whaleFlow = result.whaleFlow || {};
  const holderAnalysis = result.holderAnalysis || {};
  const smartMoneySignal = holderAnalysis.smartMoneySignal || {};
  const marketConcentration = holderAnalysis.marketConcentration || {};

  return {
    market: {
      title: selectedMarket.title,
      slug: selectedMarket.slug,
      conditionId: selectedMarket.conditionId,
      url: selectedMarket.url,
      selectionReason: selectedMarket.selectionReason,
    },
    whaleFlow: {
      period: whaleFlow.period,
      totalTrades: whaleFlow.totalTrades,
      totalVolume: whaleFlow.totalVolume,
      divergence: whaleFlow.divergence,
      whaleActivity: whaleFlow.whaleActivity,
      flowBySize: whaleFlow.flowBySize,
    },
    holders: {
      smartMoneySignal,
      marketConcentration,
      yesWhales: result.yesWhales,
      noWhales: result.noWhales,
    },
    alignment: {
      doesWhalePositioningMatchRecentFlow:
        smartMoneySignal.direction && whaleFlow.divergence
          ? {
              direction: smartMoneySignal.direction,
              divergence: whaleFlow.divergence,
              note:
                smartMoneySignal.direction === "NEUTRAL"
                  ? "Whales are not showing a strong directional bias."
                  : "Compare the holder signal with the recent flow divergence above.",
            }
          : null,
    },
    fetchedAt: result.fetchedAt,
  };
}

