import { callMcpSkill, callMcpSkillsParallel } from "@/lib/ai/skills/mcp";
import { pickTopSemanticCandidates } from "@/lib/ai/skills/semantic-targeting";

export async function main() {
  const toolId = "294100e8-c648-4e5f-a254-95a14b56e398";

  // Plan:
  // 1) Run a bounded, read-only discovery batch across different endpoints only.
  // 2) Rank the noisy discovery results locally with deterministic semantic targeting for geopolitics.
  // 3) Select one hottest live market, then fetch direct instrument/tape data for that exact conditionId.
  // 4) Keep all local filtering, ranking, and response packaging serial after the read batch completes.
  // 5) If the first batch does not surface a reliable geopolitics candidate, use one bounded fallback discovery path.

  const initialBatch = await callMcpSkillsParallel({
    label: "geopolitics-market-discovery",
    calls: [
      {
        key: "trendingPolitics",
        toolId,
        toolName: "discover_trending_markets",
        args: {
          category: "politics",
          limit: 20,
          sortBy: "volume",
        },
      },
      {
        key: "topPolitics",
        toolId,
        toolName: "get_top_markets",
        args: {
          limit: 20,
          sortBy: "volume",
          category: "politics",
          includeNearResolved: false,
          includeEnded: false,
        },
      },
    ],
  });

