export async function main() {
  const result = await callMcpSkill({
    toolId: "294100e8-c648-4e5f-a254-95a14b56e398",
    toolName: "summarize_live_market_activity",
    args: {
      endingWithinDays: 7,
      sortBy: "ending_soon",
      tradeLimit: 20
    }
  });

  const selectedMarket = result?.selectedMarket || {};
  const tradesSummary = result?.tradesSummary || {};
  const openInterest = result?.openInterest || {};
  const recentTrades = Array.isArray(result?.recentTrades) ? result.recentTrades : [];

  const totalTrades = typeof tradesSummary.totalTrades === "number" ? tradesSummary.totalTrades : 0;
  const totalVolume = typeof tradesSummary.totalVolume === "number" ? tradesSummary.totalVolume : 0;
  const buyVolume = typeof tradesSummary.buyVolume === "number" ? tradesSummary.buyVolume : 0;
  const sellVolume = typeof tradesSummary.sellVolume === "number" ? tradesSummary.sellVolume : 0;
  const avgPrice = typeof tradesSummary.avgPrice === "number" ? tradesSummary.avgPrice : null;
  const oiValue = typeof openInterest.value === "number" ? openInterest.value : null;

  const buyShare = totalVolume > 0 ? buyVolume / totalVolume : null;
  const sellShare = totalVolume > 0 ? sellVolume / totalVolume : null;

  let conviction = "noise";
  let reason = "Activity looks mixed or too thin to call it strong conviction.";

  if (totalTrades >= 15 && totalVolume > 0) {
    const imbalance = buyShare !== null && sellShare !== null ? Math.abs(buyShare - sellShare) : 0;
    const oiVsVolume = oiValue !== null && totalVolume > 0 ? oiValue / totalVolume : null;

    if (imbalance >= 0.2 && oiVsVolume !== null && oiVsVolume >= 1) {
      conviction = "genuine conviction";
      reason = "Trade flow is meaningfully one-sided and open interest is large relative to recent volume.";
    } else if (imbalance >= 0.1 || (oiVsVolume !== null && oiVsVolume >= 0.5)) {
      conviction = "some conviction";
      reason = "There is a directional lean or sustained open interest, but not enough to call it decisive.";
    } else {
      conviction = "noise";
      reason = "The tape is active, but flow is fairly balanced and open interest does not strongly confirm a thesis.";
    }
  }

  return {
    market: selectedMarket.title || null,
    conditionId: selectedMarket.conditionId || null,
    url: selectedMarket.url || null,
    endDate: selectedMarket.endDate || null,
    category: selectedMarket.category || null,
    activity: {
      totalTrades,
      totalVolume,
      buyVolume,
      sellVolume,
      avgPrice,
      openInterest: oiValue,
      recentTradeCountReturned: recentTrades.length
    },
    convictionAssessment: {
      label: conviction,
      reason
    },
    recentTradesSample: recentTrades.slice(0, 5),
    note: "This is based on a past query result from the tool run in this chat."
  };
}

